import{_ as a,c as i,o,ag as t}from"./chunks/framework.Cycwnjj0.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":null}'),r={name:"changelog.md"};function n(l,e,s,d,c,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><blockquote><p><strong>Note</strong>: This project was renamed from <code>exiftool-rs</code> to <code>oxidex</code>. Historical entries below use the old name.</p></blockquote><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="unreleased" tabindex="-1">[Unreleased] <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><h2 id="_1-2-1-2025-11-19" tabindex="-1">[1.2.1] - 2025-11-19 <a class="header-anchor" href="#_1-2-1-2025-11-19" aria-label="Permalink to &quot;[1.2.1] - 2025-11-19&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>CI/CD Automation</strong>: GitHub Pages changelog now updates automatically when a release is created <ul><li>New <code>update-docs</code> job in release workflow extracts changelog entry from main branch</li><li>Automatically commits and pushes to gh-pages branch after successful release</li><li>Eliminates manual documentation updates for releases</li></ul></li></ul><h2 id="_1-2-0-2025-11-19" tabindex="-1">[1.2.0] - 2025-11-19 <a class="header-anchor" href="#_1-2-0-2025-11-19" aria-label="Permalink to &quot;[1.2.0] - 2025-11-19&quot;">​</a></h2><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>CI/CD Infrastructure</strong>: Migrated release workflow from GitHub-hosted runners to self-hosted runners <ul><li>Moved create-release job from <code>ubuntu-latest</code> to <code>arc-runner-set</code></li><li>Migrated Windows builds from <code>windows-latest</code> to <code>arc-runner-set</code> with MinGW cross-compilation</li><li>Changed Windows target from <code>x86_64-pc-windows-msvc</code> to <code>x86_64-pc-windows-gnu</code></li><li>Configured cross-compilation linker for Windows builds from Linux</li><li>All release artifacts now built on self-hosted infrastructure except macOS (warp-macos-15-arm64-6x)</li></ul></li></ul><h2 id="_1-1-0-2025-11-17" tabindex="-1"><a href="https://github.com/swack-tools/oxidex/releases/tag/v1.1.0" target="_blank" rel="noreferrer">1.1.0</a> - 2025-11-17 <a class="header-anchor" href="#_1-1-0-2025-11-17" aria-label="Permalink to &quot;[1.1.0] - 2025-11-17&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Phase 1: Video/Audio Format Support</strong> - Complete parser implementation for 12 new multimedia formats <ul><li><strong>Video Formats (5)</strong>: <ul><li>MKV (Matroska) - Container metadata extraction</li><li>WebM - Web-optimized Matroska variant</li><li>FLV - Flash Video format</li><li>AVI - RIFF-based video container</li><li>MTS/M2TS - AVCHD/Blu-ray MPEG transport streams</li></ul></li><li><strong>Audio Formats (7)</strong>: <ul><li>MP3 - ID3v2 tag parsing</li><li>FLAC - Native metadata blocks</li><li>AAC - ADTS header parsing</li><li>WAV - RIFF INFO chunks</li><li>OGG Vorbis - Vorbis comments</li><li>Opus - Ogg Opus metadata</li><li>APE - Monkey&#39;s Audio format</li></ul></li><li><strong>Features</strong>: <ul><li>ExifTool tag namespace parity (Matroska, FLV, RIFF, ID3, FLAC, AAC, Vorbis, Opus, APE)</li><li>Comprehensive integration tests for all formats (requires ExifTool)</li><li>Full benchmark suite (audio_benchmarks.rs, video_benchmarks.rs)</li><li>Format detection support for all 12 new types</li></ul></li><li><strong>Performance</strong>: Pure Rust parsing with memory-mapped I/O</li></ul></li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>BREAKING</strong>: Project renamed from <code>exiftool-rs</code> to <code>oxidex</code><ul><li>Binary renamed: <code>exiftool-rs</code> → <code>oxidex</code></li><li>Library renamed: <code>exiftool_rs</code> → <code>oxidex</code></li><li>All crates renamed: <code>exiftool-tags*</code> → <code>oxidex-tags*</code></li><li>Install with: <code>cargo install oxidex</code></li><li>GitHub repository: <code>swack-tools/oxidex</code></li></ul></li><li><strong>Dependency Upgrades</strong>: Updated all major dependencies to latest versions for improved performance and security <ul><li><code>criterion</code> 0.5 → 0.7 - Modern benchmarking framework with improved measurement accuracy</li><li><code>indicatif</code> 0.17 → 0.18 - Enhanced progress bar library with better terminal compatibility</li><li><code>nom</code> 7.1 → 8.0 - Binary parser combinator with refined error handling and improved performance</li><li><code>quick-xml</code> 0.31 → 0.38 - XML parser for XMP metadata with enhanced API and better namespace support</li><li><code>bincode</code> 1.3 → 2.0 - Binary serialization across all tag workspace crates with new encoding API</li><li><strong>Breaking Changes Addressed:</strong><ul><li>Bincode: Migrated from <code>serialize</code>/<code>deserialize</code> to <code>encode</code>/<code>decode</code> API across 6 workspace crates</li><li>Bincode: Regenerated all tag database binary files with new format</li><li>Nom: Updated parser error types and combinator APIs</li><li>Quick-xml: Migrated Reader and Event APIs to 0.38 interface</li></ul></li><li><strong>Verification:</strong><ul><li>All 800+ unit tests passing</li><li>Benchmarks compile successfully (note: <code>criterion::black_box</code> deprecation warnings present)</li><li>CLI tested and verified with JPEG, PNG, PDF, and TIFF formats</li><li>Clean build from scratch successful</li></ul></li></ul></li></ul><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><p><strong>Canon MakerNotes Phase 1</strong>: Basic Canon-specific metadata extraction from EXIF MakerNote tags</p><ul><li><strong>Supported Tags:</strong><ul><li><code>Canon:ImageType</code> - Image type identifier (e.g., &quot;IMG:EOS R5&quot;)</li><li><code>Canon:FirmwareVersion</code> - Camera firmware version</li><li><code>Canon:OwnerName</code> - Camera owner name</li><li><code>Canon:SerialNumber</code> - Camera serial number</li><li><code>Canon:CanonModelID</code> - Canon-specific model identifier</li><li><code>Canon:FileNumber</code> - Internal file number assigned by camera</li></ul></li><li><strong>Implementation Details:</strong><ul><li>Parses Canon MakerNote IFD structure (TIFF-based format)</li><li>Supports both little-endian and big-endian byte orders</li><li>Handles both inline values (≤4 bytes) and offset-based values (&gt;4 bytes)</li><li>Gracefully handles missing or invalid MakerNote data</li></ul></li><li><strong>Phase 2 Preview:</strong> Complex array tags (CameraSettings, ShotInfo, AFInfo, LensInfo) planned for next phase</li><li><strong>Files Added:</strong><ul><li><code>src/parsers/tiff/makernotes/mod.rs</code> - MakerNotes module structure</li><li><code>src/parsers/tiff/makernotes/canon.rs</code> - Canon MakerNote parser with comprehensive documentation</li></ul></li><li><strong>Integration:</strong> Canon MakerNotes are automatically extracted from JPEG EXIF data when present</li></ul></li><li><p><strong>Canon MakerNotes Phase 2</strong>: Complex array tag support for camera settings and shot information</p><ul><li><strong>CameraSettings Array (tag 0x0001) - 8 tags:</strong><ul><li><code>Canon:MacroMode</code> - Macro mode setting (Macro, Normal)</li><li><code>Canon:Quality</code> - Image quality (Economy, Normal, Fine, Superfine, RAW, CRAW)</li><li><code>Canon:FlashMode</code> - Flash mode (Off, Auto, On, Red-eye Reduction, etc.)</li><li><code>Canon:DriveMode</code> - Drive mode (Single, Continuous, Movie, etc.)</li><li><code>Canon:FocusMode</code> - Focus mode (One-shot AF, AI Servo AF, Manual, etc.)</li><li><code>Canon:ISO</code> - ISO speed setting</li><li><code>Canon:MeteringMode</code> - Metering mode (Evaluative, Partial, Center-weighted)</li><li><code>Canon:ExposureMode</code> - Exposure mode (Program, Av, Tv, Manual, Bulb, etc.)</li></ul></li><li><strong>ShotInfo Array (tag 0x0004) - 6 tags:</strong><ul><li><code>Canon:AutoISO</code> - Auto ISO value</li><li><code>Canon:BaseISO</code> - Base ISO value</li><li><code>Canon:MeasuredEV</code> - Measured exposure value</li><li><code>Canon:TargetAperture</code> - Target aperture value</li><li><code>Canon:TargetShutterSpeed</code> - Target shutter speed</li><li><code>Canon:SubjectDistance</code> - Subject distance in mm</li></ul></li><li><strong>FocalLength Array (tag 0x0002) - 2 tags:</strong><ul><li><code>Canon:FocalType</code> - Focal length type</li><li><code>Canon:FocalLength</code> - Focal length in mm</li></ul></li><li><strong>Implementation Details:</strong><ul><li>Added <code>extract_i16_array()</code> helper for Canon&#39;s integer array tags</li><li>Supports both inline (≤2 values) and offset-based (&gt;2 values) arrays</li><li>Value decoders convert numeric codes to human-readable strings</li><li>Based on ExifTool Canon.pm reference implementation</li><li>All values gracefully handle missing/invalid data</li></ul></li><li><strong>Files Modified:</strong><ul><li><code>src/parsers/tiff/makernotes/canon.rs</code> (+400 lines of tests and implementation)</li></ul></li></ul></li><li><p><strong>CI/CD</strong>: New <code>cross-compile</code> job in CI workflow that tests both ARM64 (<code>aarch64-unknown-linux-musl</code>) and x86_64 (<code>x86_64-unknown-linux-musl</code>) Linux builds using the <code>cross</code> tool with QEMU emulation support.</p></li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>CI/CD</strong>: Fixed ARM64 cross-compilation in GitHub Actions by implementing QEMU emulation. Previously, attempting to run ARM64 Docker images (<code>ghcr.io/cross-rs/aarch64-unknown-linux-musl</code>) on x86_64 runners resulted in &quot;exec format error&quot;. The fix adds <code>docker/setup-qemu-action</code> and <code>docker/setup-buildx-action</code> to enable multi-platform builds on x86_64 runners.</li></ul><h2 id="_1-0-0-2025-10-30" tabindex="-1"><a href="https://github.com/swack-tools/oxidex/releases/tag/v1.0.0" target="_blank" rel="noreferrer">1.0.0</a> - 2025-10-30 <a class="header-anchor" href="#_1-0-0-2025-10-30" aria-label="Permalink to &quot;[1.0.0] - 2025-10-30&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><h4 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h4><ul><li><strong>Multi-format metadata extraction</strong> supporting 50+ file formats: <ul><li>JPEG (EXIF, JFIF, XMP, IPTC, Photoshop)</li><li>PNG (eXIf, tEXt, zTXt, iTXt chunks)</li><li>TIFF (multi-page support, sub-IFDs)</li><li>PDF (Info dictionary, XMP metadata)</li><li>MP4/QuickTime (atoms and metadata tracks)</li><li>RAW formats and camera maker notes</li></ul></li><li><strong>Comprehensive tag database</strong> with 700+ metadata tags automatically generated from ExifTool source</li><li><strong>Format families support</strong>: EXIF (244 tags), GPS (32 tags), IPTC (122 tags), QuickTime (143 tags), RIFF (46 tags), ICC_Profile (42 tags), Photoshop (35 tags), PNG (30 tags), JPEG (30 tags), XMP, and more</li></ul><h4 id="cli-application" tabindex="-1">CLI Application <a class="header-anchor" href="#cli-application" aria-label="Permalink to &quot;CLI Application&quot;">​</a></h4><ul><li><strong>Full CLI implementation</strong> with backward compatibility for 90% of common ExifTool usage patterns</li><li><strong>Batch processing</strong> with parallel execution using Rayon for multi-core performance</li><li><strong>Recursive directory traversal</strong> with <code>-r</code> flag for processing entire folder structures</li><li><strong>Flexible output formats</strong>: human-readable, JSON, CSV</li><li><strong>File preservation options</strong>: backup originals, preserve timestamps</li><li><strong>Advanced metadata operations</strong>: <ul><li>Read and display metadata (<code>exiftool-rs file.jpg</code>)</li><li>Write and modify metadata (<code>exiftool-rs -Artist=&quot;Name&quot; file.jpg</code>)</li><li>Copy metadata between files (<code>-TagsFromFile</code> support)</li><li>Date/time shifting for batch timestamp corrections</li><li>File renaming based on metadata patterns</li></ul></li></ul><h4 id="library-api" tabindex="-1">Library API <a class="header-anchor" href="#library-api" aria-label="Permalink to &quot;Library API&quot;">​</a></h4><ul><li><strong>Clean Rust library API</strong> with hexagonal architecture design</li><li><strong>Zero-copy parsing</strong> for efficient memory usage</li><li><strong>Type-safe metadata operations</strong> with comprehensive tag validation</li><li><strong>Extensible parser system</strong> for adding new format support</li><li><strong>Memory-mapped I/O</strong> for handling large files efficiently</li></ul><h4 id="cross-language-integration" tabindex="-1">Cross-Language Integration <a class="header-anchor" href="#cross-language-integration" aria-label="Permalink to &quot;Cross-Language Integration&quot;">​</a></h4><ul><li><strong>C FFI bindings</strong> (<code>staticlib</code> and <code>cdylib</code> crate types) for integration with C/C++, Python, Node.js, and other languages</li><li><strong>Auto-generated C headers</strong> using cbindgen with CI verification</li><li><strong>Python ctypes bindings</strong> with comprehensive examples and documentation</li><li><strong>FFI safety guarantees</strong> with proper error handling across language boundaries</li></ul><h4 id="build-distribution" tabindex="-1">Build &amp; Distribution <a class="header-anchor" href="#build-distribution" aria-label="Permalink to &quot;Build &amp; Distribution&quot;">​</a></h4><ul><li><strong>Automated tag database generation</strong> from ExifTool Perl source during build</li><li><strong>Cross-compilation support</strong> for Linux (x86_64, ARM64), macOS (Intel, Apple Silicon), Windows (x86_64)</li><li><strong>Automated release pipeline</strong> with GitHub Actions building binaries on git tag push</li><li><strong>Package formats</strong>: <ul><li>Debian packages (.deb) for Ubuntu/Debian</li><li>RPM packages for Fedora/RHEL/CentOS</li><li>Homebrew formula for macOS</li><li>Static binaries (musl libc) with no runtime dependencies</li></ul></li><li><strong>Release profile optimizations</strong>: LTO, codegen-units=1, strip=true for maximum performance</li></ul><h4 id="testing-quality" tabindex="-1">Testing &amp; Quality <a class="header-anchor" href="#testing-quality" aria-label="Permalink to &quot;Testing &amp; Quality&quot;">​</a></h4><ul><li><strong>Comprehensive test suite</strong> with 100+ integration tests</li><li><strong>Automated ExifTool comparison tests</strong> validating parity with Perl ExifTool</li><li><strong>102-image test corpus</strong> covering diverse real-world scenarios</li><li><strong>Continuous fuzzing</strong> infrastructure for PDF and MP4 parsers with libFuzzer</li><li><strong>Performance benchmarks</strong> using Criterion and hyperfine</li><li><strong>CI/CD pipeline</strong> with automated testing, linting, and formatting checks</li></ul><h4 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h4><ul><li><strong>Comprehensive user guide</strong> (mdBook) with GitHub Pages deployment at <code>docs/book/</code>: <ul><li>Installation instructions for all platforms</li><li>CLI usage guide with examples</li><li>Library API documentation with code samples</li><li>FFI integration guide for C and Python</li><li>Supported formats and tag reference</li><li>Architecture overview and design rationale</li></ul></li><li><strong>API documentation</strong>: Rust library API reference and C FFI API specification</li><li><strong>Migration guide</strong> from Perl ExifTool with compatibility notes</li></ul><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><p>OxiDex delivers exceptional performance improvements over Perl ExifTool (version 13.36) on Apple M4 hardware:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Perl ExifTool</th><th>OxiDex</th><th>Speedup</th></tr></thead><tbody><tr><td>Single JPEG read</td><td>37.5ms ± 0.5ms</td><td>2.3ms ± 0.1ms</td><td><strong>16.1x faster</strong></td></tr><tr><td>Batch processing (1000 files)</td><td>916.4ms ± 8.0ms</td><td>14.1ms ± 0.3ms</td><td><strong>64.9x faster</strong></td></tr><tr><td>Write operation (modify EXIF)</td><td>96.8ms ± 1.3ms</td><td>7.3ms ± 0.6ms</td><td><strong>13.3x faster</strong></td></tr><tr><td>Format detection</td><td>39.3ms ± 0.4ms</td><td>2.8ms ± 0.1ms</td><td><strong>14.2x faster</strong></td></tr></tbody></table><p><strong>Key optimizations:</strong></p><ul><li>Zero-cost abstractions and compiled code eliminate interpreter overhead</li><li>Parallel processing with Rayon leverages all CPU cores for batch operations</li><li>Memory-mapped I/O and efficient binary manipulation</li><li>SIMD-friendly data layouts for future vectorization</li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li><strong>Memory safety</strong> guaranteed by Rust&#39;s ownership system (zero buffer overflows, use-after-free, or data races)</li><li><strong>Continuous fuzzing</strong> with libFuzzer detecting crashes, hangs, and undefined behavior</li><li><strong>Safe parser design</strong> with explicit bounds checking and error propagation</li><li><strong>No unsafe code</strong> in critical parsing paths (FFI layer uses minimal <code>unsafe</code> with safety invariants)</li></ul><h3 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h3><p>These features are planned for future releases (v1.1+):</p><ul><li><strong>Array type validation</strong>: ValueType::Array not yet supported in validation system (src/core/validation.rs:167) <ul><li>Current impact: Array-valued metadata can bypass type checking</li><li>Workaround: Manual validation for array-valued tags</li></ul></li><li><strong>TIFF writer limitations</strong>: Float, Struct, and Array tag values not yet implemented in TIFF writer (src/writers/tiff_writer.rs:474-477) <ul><li>Current impact: These value types are silently skipped during TIFF write operations</li><li>Workaround: Use supported types (Integer, Text, Binary, Rational)</li></ul></li><li><strong>Rational round-trip parsing</strong>: TIFF parser may convert Rational values to Integer/Binary when type information is unavailable (tests/integration/write_operations_tests.rs:362) <ul><li>Current impact: Rational value precision may be lost in some round-trip scenarios</li><li>Workaround: Ensure EXIF type information is present</li></ul></li></ul><h2 id="unreleased-1" tabindex="-1">[Unreleased] <a class="header-anchor" href="#unreleased-1" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><h3 id="future-enhancements-roadmap" tabindex="-1">Future Enhancements (Roadmap) <a class="header-anchor" href="#future-enhancements-roadmap" aria-label="Permalink to &quot;Future Enhancements (Roadmap)&quot;">​</a></h3><p><strong>Phase 2 (v1.1 - v2.0): Expansion &amp; Performance</strong></p><ul><li>Expand to 150+ formats (obscure camera formats, extended maker notes)</li><li>SIMD optimizations for bulk operations (UTF-8 validation, checksums)</li><li>WebAssembly build for browser-based metadata extraction</li><li>Profile-guided optimization (PGO) builds</li><li>Incremental metadata updates (avoid full file rewrites)</li></ul><p><strong>Phase 3 (v2.1+): Ecosystem &amp; Intelligence</strong></p><ul><li>Machine learning integration for tag suggestion and auto-correction</li><li>Cloud storage integration (S3, Azure Blob with async I/O)</li><li>Metadata analytics and query DSL</li><li>Optional GUI (egui framework)</li><li>Streaming API for real-time video metadata processing</li><li>Distributed processing for million-file archives</li></ul><hr><h2 id="release-notes" tabindex="-1">Release Notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release Notes&quot;">​</a></h2><h3 id="v1-0-0-initial-stable-release" tabindex="-1">v1.0.0: Initial Stable Release <a class="header-anchor" href="#v1-0-0-initial-stable-release" aria-label="Permalink to &quot;v1.0.0: Initial Stable Release&quot;">​</a></h3><p>OxiDex achieves its foundational milestone with a fully-featured, production-ready metadata management tool. This release completes <strong>Phase 1: Foundation &amp; Adoption</strong> with:</p><ul><li><strong>50+ format support</strong> covering 90% of common use cases (JPEG, PNG, TIFF, PDF, MP4, RAW formats)</li><li><strong>16-65x performance improvement</strong> over Perl ExifTool through compiled code and parallel processing</li><li><strong>Memory safety guarantees</strong> eliminating entire classes of security vulnerabilities</li><li><strong>Cross-platform binaries</strong> for Linux, macOS, Windows with zero runtime dependencies</li><li><strong>Comprehensive documentation</strong> and migration guide for Perl ExifTool users</li></ul><p>This release is suitable for production use in:</p><ul><li>Automated media processing pipelines</li><li>Digital asset management systems</li><li>Photography workflow automation</li><li>Embedded systems requiring native binaries</li><li>Cross-language integration via C FFI (Python, Node.js, Go, etc.)</li></ul><p><strong>Migration from Perl ExifTool</strong>: OxiDex is designed as a drop-in replacement for 90% of common workflows. See the migration guide in <code>docs/book/src/migration.md</code> for compatibility notes and feature differences.</p><p><strong>Installation</strong>: <code>cargo install oxidex</code> or download pre-built binaries from <a href="https://github.com/swack-tools/oxidex/releases/tag/v1.0.0" target="_blank" rel="noreferrer">GitHub Releases</a>.</p><hr>',62)])])}const h=a(r,[["render",n]]);export{m as __pageData,h as default};
